#include "masked_cumsum_custom_tiling.h"
#include "register/op_def_registry.h"

namespace optiling {

static constexpr uint32_t UB_BUDGET_BYTES = 192 * 1024;
static constexpr uint32_t ALIGN_ELEMS = 32;   // alignment for DMA
static constexpr uint32_t MAX_TILE_ELEMS = 16384;  // safe limit per tile

static inline uint32_t AlignDown(uint32_t x, uint32_t a) {
    return (x / a) * a;
}

static inline uint32_t CeilDiv(uint32_t a, uint32_t b) {
    return (a + b - 1u) / b;
}

static ge::graphStatus TilingFunc(gert::TilingContext *context) {
    MaskedCumsumCustomTilingData tiling;
    const gert::Shape *inShape = context->GetInputShape(0);
    const uint32_t numDims = inShape->GetOriginShape().GetDimNum();
    const auto &dims = inShape->GetOriginShape().GetDims();

    // Only support 1D or 2D tensors
    if (numDims > 2) return ge::GRAPH_FAILED;

    // Get dim attribute
    const gert::RuntimeAttrs *attrs = context->GetAttrs();
    const int64_t *dimPtr = attrs->GetAttrPointer<int64_t>(0);
    int64_t dim = (dimPtr != nullptr) ? *dimPtr : 1;

    // Compute rowLength and totalLength
    uint32_t totalLength = static_cast<uint32_t>(inShape->GetOriginShape().GetShapeSize());
    uint32_t rowLength = 0;
    if (numDims == 1) {
        rowLength = static_cast<uint32_t>(dims[0]);
    } else { // numDims == 2
        if (dim == 0) {
            rowLength = static_cast<uint32_t>(dims[0]);
        } else { // dim == 1
            rowLength = static_cast<uint32_t>(dims[1]);
        }
    }

    // Compute tile length based on UB budget (2 buffers of tile size)
    uint32_t maxTile = UB_BUDGET_BYTES / (2 * sizeof(float));
    maxTile = std::min(maxTile, MAX_TILE_ELEMS);
    maxTile = AlignDown(maxTile, ALIGN_ELEMS);
    if (maxTile == 0) maxTile = ALIGN_ELEMS;

    uint32_t tileLength = std::min(rowLength, maxTile);
    // Ensure tileLength > 0
    if (tileLength == 0) tileLength = rowLength;

    // Number of sequences (rows or columns) = totalLength / rowLength
    uint32_t seqCount = totalLength / rowLength;

    // Set block dimension: use a fixed number of blocks for grid stride
    uint32_t blockDim = 24;
    if (seqCount < blockDim) blockDim = seqCount;
    if (blockDim == 0) blockDim = 1;

    context->SetBlockDim(blockDim);

    tiling.set_totalLength(totalLength);
    tiling.set_rowLength(rowLength);
    tiling.set_tileLength(tileLength);
    tiling.set_blockDim(blockDim);

    tiling.SaveToBuffer(context->GetRawTilingData()->GetData(),
                        context->GetRawTilingData()->GetCapacity());
    context->GetRawTilingData()->SetDataSize(tiling.GetDataSize());

    size_t *currentWorkspace = context->GetWorkspaceSizes(1);
    currentWorkspace[0] = 0;
    return ge::GRAPH_SUCCESS;
}

} // namespace optiling

