kernel_src="""

#include "kernel_operator.h"

class KernelMaskedCumsumCustom {
public:
    __aicore__ inline KernelMaskedCumsumCustom() {}

    __aicore__ inline void Init(GM_ADDR x, GM_ADDR mask, GM_ADDR y,
                                uint32_t totalLength, uint32_t rowLength,
                                uint32_t tileLength, uint32_t blockDim)
    {
        totalLen_ = totalLength;
        rowLen_ = rowLength;
        tileLen_ = tileLength;
        blockDim_ = blockDim;

        xGm_.SetGlobalBuffer((__gm__ float*)x, totalLen_);
        maskGm_.SetGlobalBuffer((__gm__ float*)mask, totalLen_);
        yGm_.SetGlobalBuffer((__gm__ float*)y, totalLen_);
    }

    __aicore__ inline void Process()
    {
        if (totalLen_ == 0 || rowLen_ == 0 || tileLen_ == 0) return;

        uint32_t blockNum = static_cast<uint32_t>(AscendC::GetBlockNum());
        uint32_t blockIdx = static_cast<uint32_t>(AscendC::GetBlockIdx());

        // Number of sequences (e.g., rows if dim=1 for 2D)
        uint32_t seqCount = totalLen_ / rowLen_;

        // Grid stride over sequences
        for (uint32_t seq = blockIdx; seq < seqCount; seq += blockNum) {
            uint32_t baseOffset = seq * rowLen_;
            float accum = 0.0f;

            // Process the sequence in tiles
            for (uint32_t tileStart = 0; tileStart < rowLen_; tileStart += tileLen_) {
                uint32_t curTileLen = rowLen_ - tileStart;
                if (curTileLen > tileLen_) curTileLen = tileLen_;

                // Allocate local buffers for this tile
                AscendC::LocalTensor<float> xLocal = pipe_.AllocTensor<float>(curTileLen);
                AscendC::LocalTensor<float> maskLocal = pipe_.AllocTensor<float>(curTileLen);

                // Copy x and mask from global to local
                AscendC::DataCopy(xLocal, xGm_[baseOffset + tileStart], curTileLen);
                AscendC::DataCopy(maskLocal, maskGm_[baseOffset + tileStart], curTileLen);

                // Elementwise multiply: x = x * mask
                AscendC::Mul(xLocal, xLocal, maskLocal, curTileLen);
                pipe_.FreeTensor(maskLocal);

                // In-place prefix sum with carry
                for (uint32_t i = 0; i < curTileLen; i++) {
                    accum += xLocal(i);
                    xLocal(i) = accum;
                }

                // Copy result to global output
                AscendC::DataCopy(yGm_[baseOffset + tileStart], xLocal, curTileLen);
                pipe_.FreeTensor(xLocal);
            }
        }
    }

private:
    AscendC::TPipe pipe_;
    AscendC::GlobalTensor<float> xGm_;
    AscendC::GlobalTensor<float> maskGm_;
    AscendC::GlobalTensor<float> yGm_;

    uint32_t totalLen_ {0};
    uint32_t rowLen_ {0};
    uint32_t tileLen_ {0};
    uint32_t blockDim_ {1};
};

extern "C" __global__ __aicore__ void masked_cumsum_custom(
    GM_ADDR x, GM_ADDR mask, GM_ADDR y, GM_ADDR workspace, GM_ADDR tiling)
{
    GET_TILING_DATA(tiling_data, tiling);
    KernelMaskedCumsumCustom op;
    op.Init(x, mask, y,
            tiling_data.totalLength, tiling_data.rowLength,
            tiling_data.tileLength, tiling_data.blockDim);
    op.Process();
}
